--- a/packages/ui/src/engine/pixel-characters.ts
@@ -3027,6 +3027,74 @@
+// ─── Room Transition System ────────────────────────────────────────
+
+interface TransitionState {
+  active: boolean;
+  fromType: CharacterType | null;
+  toType: CharacterType | null;
+  progress: number; // 0 to 1
+  duration: number; // in frames
+  easing: (t: number) => number;
+  effect: 'fade' | 'slide';
+  direction: 'left' | 'right' | 'up' | 'down'; // for slide effect
+}
+
+const transitionState: TransitionState = {
+  active: false,
+  fromType: null,
+  toType: null,
+  progress: 0,
+  duration: 30,
+  easing: (t) => t * t * (3 - 2 * t), // smoothstep easing
+  effect: 'fade',
+  direction: 'left',
+};
+
+/**
+ * Initiate a room transition animation.
+ * @param fromType Current room type
+ * @param toType Target room type
+ * @param effect Transition effect: 'fade' or 'slide'
+ * @param duration Duration in frames
+ * @param direction Direction for slide effect
+ */
+export function transitionToRoom(
+  fromType: CharacterType,
+  toType: CharacterType,
+  effect: 'fade' | 'slide' = 'fade',
+  duration: number = 30,
+  direction: 'left' | 'right' | 'up' | 'down' = 'left',
+) {
+  if (transitionState.active) return; // ignore if already transitioning
+  transitionState.active = true;
+  transitionState.fromType = fromType;
+  transitionState.toType = toType;
+  transitionState.progress = 0;
+  transitionState.duration = duration;
+  transitionState.effect = effect;
+  transitionState.direction = direction;
+}
+
+/**
+ * Update the transition progress by one frame.
+ * Returns true if transition is ongoing, false if finished.
+ */
+export function updateTransition(): boolean {
+  if (!transitionState.active) return false;
+  transitionState.progress += 1 / transitionState.duration;
+  if (transitionState.progress >= 1) {
+    transitionState.progress = 1;
+    transitionState.active = false;
+    return false;
+  }
+  return true;
+}
+
+/**
+ * Render the transition effect between two rooms.
+ * @param ctx CanvasRenderingContext2D
+ * @param x X position of room rendering
+ * @param y Y position of room rendering
+ * @param w Width of room rendering
+ * @param h Height of room rendering
+ * @param frame Current animation frame
+ */
+export function renderRoomTransition(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  w: number,
+  h: number,
+  frame: number,
+) {
+  if (!transitionState.active || !transitionState.fromType || !transitionState.toType) return;
+  const t = transitionState.easing(transitionState.progress);
+
+  if (transitionState.effect === 'fade') {
+    // Draw from room with decreasing opacity
+    ctx.save();
+    ctx.globalAlpha = 1 - t;
+    drawRoom(ctx, transitionState.fromType, x, y, w, h, frame);
+    ctx.restore();
+
+    // Draw to room with increasing opacity
+    ctx.save();
+    ctx.globalAlpha = t;
+    drawRoom(ctx, transitionState.toType, x, y, w, h, frame);
+    ctx.restore();
+  } else if (transitionState.effect === 'slide') {
+    // Calculate offset based on direction and progress
+    let offsetX = 0, offsetY = 0;
+    switch (transitionState.direction) {
+      case 'left':
+        offsetX = -t * w;
+        break;
+      case 'right':
+        offsetX = t * w;
+        break;
+      case 'up':
+        offsetY = -t * h;
+        break;
+      case 'down':
+        offsetY = t * h;
+        break;
+    }
+    // Draw from room sliding out
+    ctx.save();
+    ctx.translate(offsetX, offsetY);
+    drawRoom(ctx, transitionState.fromType, x, y, w, h, frame);
+    ctx.restore();
+
+    // Draw to room sliding in
+    ctx.save();
+    ctx.translate(offsetX + (transitionState.direction === 'left' ? w : transitionState.direction === 'right' ? -w : 0),
+                  offsetY + (transitionState.direction === 'up' ? h : transitionState.direction === 'down' ? -h : 0));
+    drawRoom(ctx, transitionState.toType, x, y, w, h, frame);
+    ctx.restore();
+  }
+}
+
